// 构建昨日数据查询
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

return {
  json: {
    reportDate: dateStr,
    reportName: `每日数据报表_${dateStr}`,
    queries: [
      {
        name: "新增用户数",
        sql: `SELECT COUNT(DISTINCT user_id) as new_users FROM users WHERE DATE(created_at) = DATE '${dateStr}'`,
        description: "昨日新注册用户数"
      },
      {
        name: "活跃用户数",
        sql: `SELECT COUNT(DISTINCT user_id) as active_users FROM user_activity WHERE DATE(activity_date) = DATE '${dateStr}'`,
        description: "昨日活跃用户数"
      },
      {
        name: "充值数据",
        sql: `SELECT COUNT(*) as total_transactions, SUM(amount) as total_amount, COUNT(DISTINCT user_id) as paying_users FROM transactions WHERE DATE(transaction_date) = DATE '${dateStr}' AND status = 'success'`,
        description: "昨日充值统计"
      },
      {
        name: "按游戏收入统计",
        sql: `SELECT game_name, COUNT(*) as transactions, SUM(amount) as revenue FROM transactions WHERE DATE(transaction_date) = DATE '${dateStr}' AND status = 'success' GROUP BY game_name ORDER BY revenue DESC LIMIT 10`,
        description: "昨日各游戏收入Top10"
      }
    ]
  }
};

// 汇总所有查询结果
const items = $input.all();
const reportDate = items[0].json.reportDate;
const results = [];

for (const item of items) {
  const queryName = item.json.name;
  const queryDesc = item.json.description;
  const queryResult = item.json.apiResponse;

  if (queryResult && queryResult.success) {
    results.push({
      name: queryName,
      description: queryDesc,
      data: queryResult.data.rows,
      rowCount: queryResult.data.rowCount
    });
  }
}

return {
  json: {
    reportDate: reportDate,
    generatedAt: new Date().toISOString(),
    results: results
  }
};

// 格式化为Excel数据
const { reportDate, results, generatedAt } = $input.item.json;

// 构建Excel数据
const excelData = [];

// 标题行
excelData.push(['每日数据报表']);
excelData.push(['报表日期', reportDate]);
excelData.push(['生成时间', new Date(generatedAt).toLocaleString('zh-CN')]);
excelData.push([]);

// 添加各个指标
for (const result of results) {
  excelData.push([result.name]);
  excelData.push(['说明', result.description]);

  // 添加数据
  if (result.data && result.data.length > 0) {
    // 表头
    const headers = Object.keys(result.data[0]);
    excelData.push(headers);

    // 数据行
    for (const row of result.data) {
      const values = headers.map(h => row[h]);
      excelData.push(values);
    }
  } else {
    excelData.push(['无数据']);
  }

  excelData.push([]);
}

return {
  json: {
    fileName: `每日数据报表_${reportDate}.xlsx`,
    excelData: excelData,
    reportDate: reportDate,
    results: results
  }
};

